  1→//! Semantic convention constants for GenAI and Life Agent OS observability.
  2→//!
  3→//! These follow the [OTel GenAI semantic conventions](https://opentelemetry.io/docs/specs/semconv/gen-ai/)
  4→//! and extend them with Life-specific attributes under the `life.` namespace.
  5→
  6→// ─── GenAI Semantic Conventions ──────────────────────────────────────────────
  7→
  8→/// The name of the operation being performed (e.g. "chat", "text_completion").
  9→pub const GEN_AI_OPERATION_NAME: &str = "gen_ai.operation.name";
 10→
 11→/// The AI system / provider (e.g. "anthropic", "openai").
 12→pub const GEN_AI_SYSTEM: &str = "gen_ai.system";
 13→
 14→/// The model requested (e.g. "claude-sonnet-4-20250514").
 15→pub const GEN_AI_REQUEST_MODEL: &str = "gen_ai.request.model";
 16→
 17→/// Maximum number of tokens the model should generate.
 18→pub const GEN_AI_REQUEST_MAX_TOKENS: &str = "gen_ai.request.max_tokens";
 19→
 20→/// Sampling temperature.
 21→pub const GEN_AI_REQUEST_TEMPERATURE: &str = "gen_ai.request.temperature";
 22→
 23→/// Top-p (nucleus) sampling parameter.
 24→pub const GEN_AI_REQUEST_TOP_P: &str = "gen_ai.request.top_p";
 25→
 26→/// Number of input (prompt) tokens consumed.
 27→pub const GEN_AI_USAGE_INPUT_TOKENS: &str = "gen_ai.usage.input_tokens";
 28→
 29→/// Number of output (completion) tokens generated.
 30→pub const GEN_AI_USAGE_OUTPUT_TOKENS: &str = "gen_ai.usage.output_tokens";
 31→
 32→/// Reasons the model stopped generating (e.g. "stop", "tool_use", "max_tokens").
 33→pub const GEN_AI_RESPONSE_FINISH_REASONS: &str = "gen_ai.response.finish_reasons";
 34→
 35→/// Provider-assigned response ID.
 36→pub const GEN_AI_RESPONSE_ID: &str = "gen_ai.response.id";
 37→
 38→/// The model actually used (may differ from requested model).
 39→pub const GEN_AI_RESPONSE_MODEL: &str = "gen_ai.response.model";
 40→
 41→/// Tool name being called or executed.
 42→pub const GEN_AI_TOOL_NAME: &str = "gen_ai.tool.name";
 43→
 44→/// Tool call ID assigned by the model.
 45→pub const GEN_AI_TOOL_CALL_ID: &str = "gen_ai.tool.call.id";
 46→
 47→/// Agent name.
 48→pub const GEN_AI_AGENT_NAME: &str = "gen_ai.agent.name";
 49→
 50→/// Agent ID.
 51→pub const GEN_AI_AGENT_ID: &str = "gen_ai.agent.id";
 52→
 53→// ─── Server Attributes ──────────────────────────────────────────────────────
 54→
 55→/// Server hostname or IP.
 56→pub const SERVER_ADDRESS: &str = "server.address";
 57→
 58→/// Server port number.
 59→pub const SERVER_PORT: &str = "server.port";
 60→
 61→// ─── Life Agent OS Attributes (life.* namespace) ─────────────────────────────
 62→
 63→/// Agent OS session ID.
 64→pub const LIFE_SESSION_ID: &str = "life.session_id";
 65→
 66→/// Agent OS run ID (within a session).
 67→pub const LIFE_RUN_ID: &str = "life.run_id";
 68→
 69→/// Agent OS branch ID.
 70→pub const LIFE_BRANCH_ID: &str = "life.branch_id";
 71→
 72→/// Current loop phase (perceive, deliberate, gate, execute, commit, reflect, sleep).
 73→pub const LIFE_LOOP_PHASE: &str = "life.loop_phase";
