  1→//! Contract-derived span builders for the Life Agent OS.
  2→//!
  3→//! Provides helper functions that create properly-attributed `tracing` spans
  4→//! from aiOS kernel types. The `tracing-opentelemetry` layer bridges these
  5→//! to OTel spans automatically.
  6→
  7→use aios_protocol::event::{EventEnvelope, LoopPhase, TokenUsage};
  8→use tracing::Span;
  9→
 10→use crate::semconv;
 11→
 12→/// Create a root `invoke_agent` span for an agent session.
 13→///
 14→/// This is the top-level span for an agent invocation, containing all
 15→/// loop phases and LLM calls as children.
 16→pub fn agent_span(session_id: &str, agent_name: &str) -> Span {
 17→    tracing::info_span!(
 18→        "invoke_agent",
 19→        { semconv::GEN_AI_OPERATION_NAME } = "invoke_agent",
 20→        { semconv::GEN_AI_AGENT_NAME } = agent_name,
 21→        { semconv::GEN_AI_AGENT_ID } = session_id,
 22→        { semconv::LIFE_SESSION_ID } = session_id,
 23→    )
 24→}
 25→
 26→/// Create a child span for a loop phase.
 27→pub fn phase_span(phase: LoopPhase) -> Span {
 28→    let phase_str = match phase {
 29→        LoopPhase::Perceive => "perceive",
 30→        LoopPhase::Deliberate => "deliberate",
 31→        LoopPhase::Gate => "gate",
 32→        LoopPhase::Execute => "execute",
 33→        LoopPhase::Commit => "commit",
 34→        LoopPhase::Reflect => "reflect",
 35→        LoopPhase::Sleep => "sleep",
 36→    };
 37→
 38→    tracing::info_span!("loop_phase", { semconv::LIFE_LOOP_PHASE } = phase_str,)
 39→}
 40→
 41→/// Create a GenAI `chat` client span for an LLM call.
 42→///
 43→/// Follows the OTel GenAI semantic convention for client spans:
 44→/// `chat {gen_ai.request.model}` naming pattern.
 45→pub fn chat_span(
 46→    model: &str,
 47→    provider: &str,
 48→    max_tokens: Option<u32>,
 49→    temperature: Option<f64>,
 50→) -> Span {
 51→    tracing::info_span!(
 52→        "chat",
 53→        { semconv::GEN_AI_OPERATION_NAME } = "chat",
 54→        { semconv::GEN_AI_SYSTEM } = provider,
 55→        { semconv::GEN_AI_REQUEST_MODEL } = model,
 56→        { semconv::GEN_AI_REQUEST_MAX_TOKENS } = max_tokens,
 57→        { semconv::GEN_AI_REQUEST_TEMPERATURE } = temperature,
 58→        // These will be filled in after the response:
 59→        { semconv::GEN_AI_USAGE_INPUT_TOKENS } = tracing::field::Empty,
 60→        { semconv::GEN_AI_USAGE_OUTPUT_TOKENS } = tracing::field::Empty,
 61→        { semconv::GEN_AI_RESPONSE_FINISH_REASONS } = tracing::field::Empty,
 62→        { semconv::GEN_AI_RESPONSE_ID } = tracing::field::Empty,
 63→    )
 64→}
 65→
 66→/// Create a GenAI `execute_tool` span for a tool call.
 67→pub fn tool_span(tool_name: &str, tool_call_id: &str) -> Span {
 68→    tracing::info_span!(
 69→        "execute_tool",
 70→        { semconv::GEN_AI_OPERATION_NAME } = "execute_tool",
 71→        { semconv::GEN_AI_TOOL_NAME } = tool_name,
 72→        { semconv::GEN_AI_TOOL_CALL_ID } = tool_call_id,
 73→        { semconv::LIFE_TOOL_STATUS } = tracing::field::Empty,
 74→    )
 75→}
 76→
 77→/// Record token usage on the current span.
 78→///
 79→/// Sets `gen_ai.usage.input_tokens` and `gen_ai.usage.output_tokens`.
 80→pub fn record_token_usage(span: &Span, usage: &TokenUsage) {
 81→    span.record(semconv::GEN_AI_USAGE_INPUT_TOKENS, usage.prompt_tokens);
 82→    span.record(semconv::GEN_AI_USAGE_OUTPUT_TOKENS, usage.completion_tokens);
 83→}
 84→
 85→/// Record the finish reason on the current span.
 86→pub fn record_finish_reason(span: &Span, reason: &str) {
 87→    span.record(semconv::GEN_AI_RESPONSE_FINISH_REASONS, reason);
 88→}
 89→
 90→/// Record the response ID on the current span.
 91→pub fn record_response_id(span: &Span, response_id: &str) {
 92→    span.record(semconv::GEN_AI_RESPONSE_ID, response_id);
 93→}
 94→
 95→/// Record tool execution status on a tool span.
 96→pub fn record_tool_status(span: &Span, status: &str) {
 97→    span.record(semconv::LIFE_TOOL_STATUS, status);
 98→}
 99→
100→/// Write the current trace context (trace_id, span_id) into an EventEnvelope.
101→///
102→/// This enables dual-write: events carry OTel correlation IDs so that
103→/// persisted events can be linked back to their traces.
104→pub fn write_trace_context(envelope: &mut EventEnvelope) {
105→    use opentelemetry::trace::TraceContextExt;
106→    use tracing_opentelemetry::OpenTelemetrySpanExt;
107→
108→    let current_span = Span::current();
109→    let otel_context = current_span.context();
110→    let span_ref = otel_context.span();
111→    let span_context = span_ref.span_context();
112→
113→    if span_context.is_valid() {
114→        envelope.trace_id = Some(span_context.trace_id().to_string());
115→        envelope.span_id = Some(span_context.span_id().to_string());
116→    }
117→}
118→
119→/// Extract trace context from a persisted EventEnvelope.
120→///
121→/// Returns `(trace_id, span_id)` if both are present.
122→pub fn extract_trace_context(envelope: &EventEnvelope) -> Option<(String, String)> {
123→    match (&envelope.trace_id, &envelope.span_id) {
124→        (Some(trace_id), Some(span_id)) if !trace_id.is_empty() && !span_id.is_empty() => {
125→            Some((trace_id.clone(), span_id.clone()))
126→        }
127→        _ => None,
128→    }
129→}
130→
131→#[cfg(test)]
132→mod tests {
133→    use super::*;
134→    use aios_protocol::event::*;
135→    use std::collections::HashMap;
136→
137→    /// Install a minimal subscriber so spans are not disabled during tests.
138→    /// Uses `try_init` to tolerate tests running in any order.
139→    fn ensure_subscriber() {
140→        let _ = tracing_subscriber::fmt().with_test_writer().try_init();
141→    }
142→
143→    fn test_envelope() -> EventEnvelope {
144→        EventEnvelope {
145→            event_id: "evt-1".into(),
146→            session_id: "sess-1".into(),
147→            agent_id: "agent-1".into(),
148→            branch_id: "main".into(),
149→            run_id: None,
150→            seq: 0,
151→            timestamp: 0,
152→            actor: EventActor {
153→                actor_type: ActorType::System,
154→                component: Some("test".to_string()),
155→            },
156→            schema: EventSchema {
157→                name: "aios-protocol".to_string(),
158→                version: "0.1.0".to_string(),
159→            },
160→            parent_id: None,
161→            trace_id: None,
162→            span_id: None,
163→            digest: None,
164→            kind: EventKind::SessionCreated {
165→                name: "test-session".to_string(),
166→                config: serde_json::Value::Object(serde_json::Map::new()),
167→            },
168→            metadata: HashMap::new(),
169→            schema_version: 1,
170→        }
171→    }
172→
173→    #[test]
174→    fn agent_span_has_correct_name() {
175→        ensure_subscriber();
176→        let span = agent_span("sess-123", "test-agent");
177→        assert!(!span.is_disabled());
178→    }
179→
180→    #[test]
181→    fn phase_span_all_variants() {
182→        ensure_subscriber();
183→        let phases = [
184→            LoopPhase::Perceive,
185→            LoopPhase::Deliberate,
186→            LoopPhase::Gate,
187→            LoopPhase::Execute,
188→            LoopPhase::Commit,
189→            LoopPhase::Reflect,
190→            LoopPhase::Sleep,
191→        ];
192→        for phase in phases {
193→            let span = phase_span(phase);
194→            assert!(!span.is_disabled());
195→        }
196→    }
197→
198→    #[test]
199→    fn chat_span_creates_valid_span() {
200→        ensure_subscriber();
201→        let span = chat_span(
202→            "claude-sonnet-4-20250514",
203→            "anthropic",
204→            Some(4096),
205→            Some(0.7),
206→        );
207→        assert!(!span.is_disabled());
208→    }
209→
210→    #[test]
211→    fn tool_span_creates_valid_span() {
212→        ensure_subscriber();
213→        let span = tool_span("read_file", "call-abc123");
214→        assert!(!span.is_disabled());
215→    }
216→
217→    #[test]
218→    fn extract_trace_context_returns_none_for_empty() {
219→        let envelope = test_envelope();
220→        assert!(extract_trace_context(&envelope).is_none());
221→    }
222→
223→    #[test]
224→    fn extract_trace_context_returns_values() {
