pub fn new_projection_map() -> ProjectionMap {
    Arc::new(RwLock::new(HashMap::new()))
}

pub async fn subscribe_session(
    journal: Arc<dyn Journal>,
    session_id: String,
    branch_id: String,
    projections: ProjectionMap,
) {
    // Lines 44-49: Subscribe initialization
    info!(
        session_id = %session_id,
        branch_id = %branch_id,
        after_seq = after_seq,
        "subscribing to Lago journal"
    );

    // Lines 51-65: Stream setup with error handling
    let stream_result = journal.stream(lago_session_id, lago_branch_id, after_seq).await;
    let mut stream = match stream_result {
        Ok(s) => s,
        Err(e) => {
            warn!(
                session_id = %session_id,
                error = %e,
                "failed to subscribe to Lago journal"
            );
            return;
        }
    };

    // Lines 67-87: Event loop — consumes stream + projects
    while let Some(result) = stream.next().await {
        match result {
            Ok(envelope) => {
                // Lines 70-77: Fold event into projection
                let ts_ms = envelope.timestamp / 1000;
                let mut map = projections.write().await;
                let state = map
                    .entry(session_id.clone())
                    .or_insert_with(|| HomeostaticState::for_agent(&session_id));
                *state = fold(state.clone(), &envelope.payload, seq, ts_ms);
            }
            Err(e) => {
                warn!(
                    session_id = %session_id,
                    error = %e,
                    "error reading from Lago journal stream"
                );
            }
        }
    }

    info!(session_id = %session_id, "Lago journal stream ended");  // Line 89
}

